class Solution {
public:
    string resultingString(string s) {
        string stack;
        for (char c : s) {
            if (!stack.empty() && (abs(stack.back() - c) == 1 || (stack.back() == 'a' && c == 'z') || (stack.back() == 'z' && c == 'a'))) {
                stack.pop_back();
            } else {
                stack.push_back(c);
            }
        }
        return stack;
    }
};
